import{_ as e,c as a,a as i,o as d}from"./app-CEcM0piI.js";const s={};function n(l,t){return d(),a("div",null,t[0]||(t[0]=[i(`<h1 id="math" tabindex="-1"><a class="header-anchor" href="#math"><span>Math</span></a></h1><p>进行数学计算的工具类,其中所有的方法都是静态的</p><table><thead><tr><th>函数</th><th>作用</th></tr></thead><tbody><tr><td>public static double ceil(double a)</td><td>向上取整</td></tr><tr><td>public static double floor(double a)</td><td>向下取整</td></tr><tr><td>public static int round(float a)</td><td>四舍五入</td></tr><tr><td>public static int max(int a,int b)</td><td>获取两个int值中的较大值</td></tr><tr><td>public static double pow(double a,double b)</td><td>返回a的b次幂的值</td></tr><tr><td>public static double random()</td><td>返回值为double的随机值，范围[0.0,1.0)</td></tr><tr><td>public static double sqrt(double a)</td><td>返回a的平方根</td></tr><tr><td>public static double cbrt(double a)</td><td>返回a的立方根</td></tr><tr><td>public static int abs(int a）</td><td>获取a的绝对值</td></tr></tbody></table><h1 id="system" tabindex="-1"><a class="header-anchor" href="#system"><span>System</span></a></h1><p>与系统相关的工具类</p><table><thead><tr><th>函数</th><th>作用</th></tr></thead><tbody><tr><td>public static void exit(int status)</td><td>终止当前运行的 Java 虚拟机</td></tr><tr><td>public static long currentTimeMillis()</td><td>返回当前系统的时间毫秒值形式</td></tr><tr><td>public static void arraycopy(数据源数组,起始索引,目的地数组,起始索引,拷贝个数)</td><td>数组拷贝<br></td></tr></tbody></table><h1 id="runtime" tabindex="-1"><a class="header-anchor" href="#runtime"><span>Runtime</span></a></h1><p>表示当前java虚拟机的运行环境 这个对象不能直接获得需要根据它的一个内部函数获得</p><table><thead><tr><th>函数</th><th>作用</th></tr></thead><tbody><tr><td>public static Runtime getRuntime()</td><td>当前系统的运行环境对象</td></tr><tr><td>public void exit(int status)</td><td>停止虚拟机. System中的exit方法就是调用此方法</td></tr><tr><td>public int availableProcessors()</td><td>获得CPU的线程数</td></tr><tr><td>public long maxMemory()</td><td>JVM能从系统中获取总内存大小（单位byte）</td></tr><tr><td>public long totalMemory()</td><td>JVM已经从系统中获取总内存大小（单位byte）</td></tr><tr><td>public longfreeMemory()</td><td>JVM剩余内存大小（单位byte）</td></tr><tr><td>public Processexec(String command)</td><td>运行cmd命令</td></tr><tr><td></td><td></td></tr></tbody></table><h1 id="object" tabindex="-1"><a class="header-anchor" href="#object"><span>Object</span></a></h1><p>Object是Java中的顶级父类。所有的类都直接或间接的继承于object类。 顶级父类中只有无参构造方法</p><table><thead><tr><th>函数</th><th>作用</th></tr></thead><tbody><tr><td>public Object()</td><td>空参构造</td></tr><tr><td>public String tostring()</td><td>返回对象的字符串表示形式</td></tr><tr><td>public boolean equals(object obj)</td><td>比较两个对象是否相等</td></tr><tr><td>protected object clone(int a)</td><td>对象克隆</td></tr></tbody></table><p>Object中的tostring一般是地址值,如果想要看属性值的话需要重写</p><p>自定义的数据类型一般都需要重写equals方法</p><ol><li>如果没有重写equals方法，那么默认使用object中的方法进行比较，比较的是地址值是否相等</li><li>一般来讲地址值对于我们意义不大，所以我们会重写，重写之后比较的就是对象内部的属性值了。</li></ol><div class="language- line-numbers-mode has-collapsed-lines collapsed" data-highlighter="shiki" data-ext="" style="--vp-collapsed-lines:15;--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>String s =&quot;abc&quot;;</span></span>
<span class="line"><span>StringBuilder sb =new StringBuilder(&quot;abc&quot;);</span></span>
<span class="line"><span></span></span>
<span class="line"><span>System.out.println(s.equals(sb));</span></span>
<span class="line"><span>// false</span></span>
<span class="line"><span>//因为equals方法是被s调用的，而s是字符串</span></span>
<span class="line"><span>//所以equals要看String类中的</span></span>
<span class="line"><span>//字符串中的equals方法，先判断参数是否为字符串</span></span>
<span class="line"><span>//如果是字符串，再比较内部的属性</span></span>
<span class="line"><span>//但是如果参数不是字符串，直接返回false</span></span>
<span class="line"><span></span></span>
<span class="line"><span>System.out.println(sb.equals(s));</span></span>
<span class="line"><span>// false</span></span>
<span class="line"><span>//因为equals方法是被sb调用的，而sb是StringBuilder</span></span>
<span class="line"><span>//所以这里的equals方法要看StringBuilder中的equals方法</span></span>
<span class="line"><span>//那么在StringBuilder当中，没有重写equals方法</span></span>
<span class="line"><span>//使用的是object中的//在object当中默认是使用==号比较两个对象的地址值</span></span>
<span class="line"><span>//而这里的s和sb记录的地址值是不一样的，所以结果返回false</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div><div class="collapsed-lines"></div></div><p><strong>clone因为是protected保护权限,只能在本包内使用,因此在使用的时候必须要在当前类重写clone方法,相当于拷贝构造</strong> Object中的clone默认是浅拷贝</p><h1 id="objects" tabindex="-1"><a class="header-anchor" href="#objects"><span>Objects</span></a></h1><p>Objects是一个工具类，提供了一些方法去完成一些功能。</p><table><thead><tr><th>函数</th><th>作用</th></tr></thead><tbody><tr><td>public boolean equals(Object a,Object b)</td><td>先做非空判断,再比较两个对象</td></tr><tr><td>public boolean isNull(Object a)</td><td>判断对象是否为空</td></tr><tr><td>public bollean nonNull(Object a)</td><td>判断对象是否非空</td></tr></tbody></table><h1 id="biginteger" tabindex="-1"><a class="header-anchor" href="#biginteger"><span>BigInteger</span></a></h1><p>对象一旦创建,内部的值无法改变</p><table><thead><tr><th>函数</th><th>作用</th></tr></thead><tbody><tr><td>public BigInteger(int num, Random rnd)</td><td>获取随机大整数，范围：[0～2的num次方-1]</td></tr><tr><td>public BigInteger(String val)</td><td>获取指定的大整数</td></tr><tr><td>public BigInteger(String val, int radix)</td><td>获取指定进制的大整数</td></tr><tr><td>public static BigInteger value0f(long val)</td><td>静态方法获取BigInteger的对象，内部有优化</td></tr><tr><td>Bigdecimal在构造时需要把值使用引号引用起来,引号内不能有除数字外的其他字符</td><td></td></tr></tbody></table><p>如果BigInteger表示的数字没有超出long的范围，可以用静态方法获取。 如果BigInteger表示的超出long的范围，可以用构造方法获取。 对象一旦创建，BigInteger内部记录的值不能发生改变。 只要进行计算都会产生一个新的BigInteger对象(如果是和0相加不会创建新的对象)</p><table><thead><tr><th>函数</th><th>作用</th></tr></thead><tbody><tr><td>public BigInteger add(BigInteger val)</td><td>加法</td></tr><tr><td>public BigInteger subtract(BigInteger val)</td><td>减法</td></tr><tr><td>public BigInteger multiply(BigInteger val)</td><td>乘法</td></tr><tr><td>public BigInteger ddivide(BigInteger val)</td><td>除法，获取商</td></tr><tr><td>public BigInteger[] divideAndRemainder(BigInteger val)</td><td>除法，获取商和余数. 返回的数组0索引是商,1索引是余数</td></tr><tr><td>public boolean equals(Object x)</td><td>比较是否相同</td></tr><tr><td>public BigInteger pow(int exponent)</td><td>次幂</td></tr><tr><td>public BigInteger max/min(BigInteger val)</td><td>返回较大值/较小值</td></tr><tr><td>publicint intValue(BigInteger val)</td><td>转为int类型整数，超出范围数据有误</td></tr></tbody></table><p>BigInteger存储方式是从左往右每32位为一组,首部加上一个符号位,符号位0表示负数,1表示正数,符号位单独为一组,然后把每组数据都转成十进制存储到一个数组中,数组的0号索引为符号位 ![[Clip_2024-09-18_22-54-25.png]]</p><h1 id="bigdecimal" tabindex="-1"><a class="header-anchor" href="#bigdecimal"><span>BigDecimal</span></a></h1><p>它有许多构造方法,但如果需要精确计算的小数只能使用字符串的构造方法</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>public BitgDeciaml(String s)</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><ol><li>如果要表示的数字不大，没有超出double的取值范围，建议使用静态方法</li><li>如果要表示的数字比较大，超出了double的取值范围，建议使用构造方法</li><li>如果我们传递的是0~10之间的整数，包含0，包含10，那么方法会返回已经创建好的对象，不会重新new</li></ol><p>也具有和Biginteger一样的基础算数运算的函数</p>`,31)]))}const c=e(s,[["render",n]]),p=JSON.parse('{"path":"/back/java/4/","title":"4 常用API","lang":"zh-CN","frontmatter":{"title":"4 常用API","createTime":"2025/04/05 12:12:26","permalink":"/back/java/4/"},"readingTime":{"minutes":4.99,"words":1497},"git":{"createdTime":1750599657000,"updatedTime":1750599657000,"contributors":[{"name":"pink","username":"pink","email":"pinkdopeybug@163.com","commits":1,"avatar":"https://avatars.githubusercontent.com/pink?v=4","url":"https://github.com/pink"}]},"filePathRelative":"notes/后端/Java/4 常用API.md","headers":[]}');export{c as comp,p as data};
